const icon=(n,c='')=>`<svg class="icon ${c}" viewBox="0 0 24 24" aria-hidden="true">${ICONS[n]||ICONS.link}</svg>`;
const $=(q,r=document)=>r.querySelector(q), $$=(q,r=document)=>[...r.querySelectorAll(q)];
const esc=(v='')=>String(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const attr=(v='')=>esc(v).replace(/`/g,'&#96;');
const slugify=(v='')=>v.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,52);
const uid=()=>`cmp-${crypto.randomUUID?.()||Math.random().toString(36).slice(2)}`;
const typeLabel=t=>({video:'Video',apk:'Aplicación APK',software:'Software',file:'Archivo',link:'Enlace externo',other:'Contenido'}[t]||'Contenido');
const typeIcon=t=>({video:'play',apk:'download',software:'monitor',file:'file',link:'link',other:'file'}[t]||'file');
const actionLabel=t=>({video:'Ver video completo',apk:'Descargar aplicación',software:'Descargar software',file:'Descargar archivo',link:'Abrir contenido',other:'Abrir contenido'}[t]||'Abrir contenido');

const state={user:null,isAdmin:false,view:'loading',settings:{brand:'VidPase',domain:'https://vidpase.github.io/'},campaigns:[],events:[],submissions:[],editor:null,pendingCover:null,pendingThumb:null,pendingChannelLogo:null,pendingReference:null,publicCampaign:null,publicStage:'intro',public:{youtubeOpened:false,watched:false,screenshotFile:null,screenshotData:'',uploading:false,guideVisible:false,guideTimer:null,promptIds:[],submissionId:'',unlockedUrl:'',retrying:false},loginError:''};

function toast(text){const n=document.createElement('div');n.className='toast';n.textContent=text;$('#toastWrap').appendChild(n);setTimeout(()=>n.remove(),3000)}
function showLoading(){setView('loading');$('#view-loading').innerHTML='<div class="loading"><div><div class="spinner"></div><p>Cargando contenido…</p></div></div>'}
function setView(view){state.view=view;$('#appMain').classList.toggle('public',view==='public');if(view!=='public')document.body.classList.remove('wizard-open');$$('.view').forEach(v=>v.classList.remove('active'));const el=$('#view-'+view);if(el)el.classList.add('active');renderHeader()}
function renderHeader(){const a=$('#headerActions');$('#brandName').textContent=state.settings.brand;$('#brandIcon').innerHTML=icon('link','icon-lg');$('#brandBtn').onclick=()=>{if(state.isAdmin)goAdmin();else if(state.publicCampaign)location.href=publicUrl(state.publicCampaign)};if(state.view==='public'){a.innerHTML=`<div class="secure-chip">${icon('shield','icon-sm')}<span>Acceso seguro y guiado</span></div>${state.isAdmin?`<button class="nav-btn" onclick="App.goAdmin()">${icon('layout','icon-sm')}Panel</button>`:''}`;return}if(state.isAdmin){a.innerHTML=`<button class="nav-btn ${state.view==='admin'?'active':''}" onclick="App.goAdmin()">${icon('layout','icon-sm')}Panel</button><button class="nav-btn ${state.view==='submissions'?'active':''}" onclick="App.showSubmissions()">${icon('camera','icon-sm')}Capturas</button><button class="nav-btn" onclick="App.logout()">${icon('logout','icon-sm')}Salir</button>`}else a.innerHTML=''}
function copyText(text,msg='Copiado al portapapeles.'){navigator.clipboard?.writeText(text).then(()=>toast(msg)).catch(()=>{const t=document.createElement('textarea');t.value=text;document.body.appendChild(t);t.select();document.execCommand('copy');t.remove();toast(msg)})}
function showModal(html){$('#modalRoot').innerHTML=`<div class="modal-backdrop"><div class="modal">${html}</div></div>`}
function closeModal(){$('#modalRoot').innerHTML=''}
function publicUrl(c){return state.settings.domain.replace(/\/+$/,'/')+encodeURIComponent(c.slug)+'/' }
function isAdminUser(u){return !!u&&u.uid===ADMIN_UID&&!u.isAnonymous}
function snapshotData(s){return {id:s.id,...s.data()}}

async function loadSettings(){try{const s=await getDoc(doc(db,'siteSettings','global'));if(s.exists())state.settings={...state.settings,...s.data()}}catch(e){console.warn('settings',e)}}
async function ensureAnonymous(){if(auth.currentUser)return auth.currentUser;const r=await signInAnonymously(auth);return r.user}
async function logEvent(type,campaignId){try{const u=auth.currentUser||await ensureAnonymous();await addDoc(collection(db,'events'),{ownerUid:u.uid,campaignId,type,createdAt:serverTimestamp()})}catch(e){console.warn('event',e)}}

function renderLogin(){setView('login');$('#view-login').innerHTML=`<div class="login-wrap"><div class="card login-card"><div class="login-mark">${icon('shield','icon-lg')}</div><span class="kicker">Panel privado</span><h1>Iniciar sesión</h1><p>Accede con el correo y contraseña del administrador de VidPase.</p>${state.loginError?`<div class="login-error">${esc(state.loginError)}</div>`:''}<form id="loginForm"><div class="field"><label class="field-label" for="loginEmail">Correo</label><input class="input" id="loginEmail" type="email" autocomplete="username" required></div><div class="field"><label class="field-label" for="loginPass">Contraseña</label><input class="input" id="loginPass" type="password" autocomplete="current-password" required></div><button class="btn btn-primary btn-wide" id="loginBtn" type="submit">${icon('shield')}Entrar al panel</button></form></div></div>`;$('#loginForm').onsubmit=login}
async function login(e){e.preventDefault();state.loginError='';const btn=$('#loginBtn');btn.disabled=true;btn.textContent='Ingresando…';try{if(auth.currentUser?.isAnonymous)await signOut(auth);const r=await signInWithEmailAndPassword(auth,$('#loginEmail').value.trim(),$('#loginPass').value);if(r.user.uid!==ADMIN_UID){await signOut(auth);throw new Error('Este usuario no tiene permisos de administrador.')}}catch(err){state.loginError=humanAuthError(err);renderLogin()}}
function humanAuthError(e){const c=e.code||'';if(c.includes('invalid-credential'))return'Correo o contraseña incorrectos.';if(c.includes('too-many-requests'))return'Demasiados intentos. Espera unos minutos.';return e.message||'No se pudo iniciar sesión.'}
async function logout(){await signOut(auth);location.href='/'}

async function loadAdminData(){
  showLoading();
  try{
    const [cSnap,eSnap,sSnap,pSnap]=await Promise.all([
      getDocs(query(collection(db,'campaigns'),orderBy('updatedAt','desc'))),
      getDocs(collection(db,'events')),
      getDocs(query(collection(db,'submissions'),orderBy('createdAt','desc'),limit(200))),
      getDocs(collection(db,'submissionPrivate'))
    ]);
    state.campaigns=cSnap.docs.map(snapshotData);
    state.events=eSnap.docs.map(snapshotData);
    const details=new Map(pSnap.docs.map(d=>[d.id,d.data()]));
    state.submissions=sSnap.docs.map(d=>({...snapshotData(d),validation:details.get(d.id)||{}}));
    renderAdmin();
  }catch(e){console.error(e);toast('No se pudieron cargar los datos de Firebase.');renderAdmin()}
}
function renderAdmin(filter=''){setView('admin');const list=state.campaigns.filter(c=>(`${c.title} ${c.slug}`).toLowerCase().includes(filter.toLowerCase()));const active=state.campaigns.filter(c=>c.status==='active').length;const views=state.events.filter(e=>e.type==='page_view').length;const done=state.events.filter(e=>e.type==='completed').length;$('#view-admin').innerHTML=`<div class="admin-hero"><div><span class="kicker">Panel privado</span><h1 class="title">Enlaces de acceso</h1><p>Administra tus enlaces, capturas y estadísticas.</p></div><button class="btn btn-primary" onclick="App.newCampaign()">${icon('plus')}Crear nuevo enlace</button></div><div class="stats"><div class="stat-card"><span>Campañas</span><strong>${state.campaigns.length}</strong></div><div class="stat-card"><span>Publicadas</span><strong>${active}</strong></div><div class="stat-card"><span>Visitas</span><strong>${views}</strong></div><div class="stat-card"><span>Completados</span><strong>${done}</strong></div></div><div class="toolbar"><input class="input" id="campaignSearch" placeholder="Buscar por título o enlace" value="${attr(filter)}"><button class="btn btn-secondary" onclick="App.editSettings()">${icon('settings')}Configuración</button></div>${list.length?`<div class="campaign-grid">${list.map(campaignCard).join('')}</div>`:`<div class="card empty"><h3>Todavía no hay enlaces creados</h3><p>Puedes crear una nueva o migrar las campañas guardadas en este navegador.</p><div style="display:flex;justify-content:center;gap:8px;flex-wrap:wrap"><button class="btn btn-primary" onclick="App.newCampaign()">${icon('plus')}Nueva campaña</button><button class="btn btn-secondary" onclick="App.migrateLocal()">${icon('refresh')}Migrar campañas actuales</button></div></div>`}`;$('#campaignSearch').oninput=e=>renderAdmin(e.target.value)}
function campaignCard(c){const views=state.events.filter(e=>e.campaignId===c.id&&e.type==='page_view').length;const completed=state.events.filter(e=>e.campaignId===c.id&&e.type==='completed').length;return `<article class="campaign-card"><div class="campaign-top"><img src="${attr(c.coverUrl||'')}" alt=""><div class="campaign-copy"><h3>${esc(c.title)}</h3><p>${esc(publicUrl(c))}</p><span class="status ${c.status==='active'?'live':'draft'}">${c.status==='active'?'Publicado':'Borrador'}</span><p style="margin-top:8px">${views} visitas · ${completed} completados</p></div></div><div class="card-actions"><button class="btn btn-soft btn-sm" onclick="App.openPublic('${c.slug}')">${icon('eye','icon-sm')}Ver</button><button class="btn btn-secondary btn-sm" onclick="App.editCampaign('${c.id}')">${icon('edit','icon-sm')}Editar</button><button class="btn btn-secondary btn-sm" onclick="App.copyLink('${c.id}')">${icon('copy','icon-sm')}Copiar</button><button class="btn btn-danger btn-sm" onclick="App.removeCampaign('${c.id}')">${icon('trash','icon-sm')}Eliminar</button></div></article>`}
function goAdmin(){if(!state.isAdmin){location.href='/';return}if(location.pathname!=='/'||location.hash){history.replaceState(null,'','/')}loadAdminData()}

function blankCampaign(){return{id:uid(),title:'',description:'',contentType:'video',format:'horizontal',coverUrl:'',videoThumbUrl:'',videoUrl:'',videoTitle:'',channel:'',channelLogoUrl:'',keyword:'',watchSeconds:30,screenshotRequired:true,commentPrompts:['La explicación fue clara y fácil de seguir.','El ejemplo práctico me ayudó a entender mejor el tema.','Gracias por mostrar el proceso paso a paso.','La parte final fue la que más me ayudó.','Me gustó que explicaras todo de forma directa.','Voy a probar este método porque se ve muy útil.','El consejo principal del video me pareció interesante.','Ahora tengo mucho más claro cómo funciona.','Buen contenido, especialmente la demostración.','¿Podrías hacer otro video profundizando en este tema?','La información está bien organizada y se entiende rápido.','El ejemplo que mostraste resolvió una duda que tenía.'],adHtml:'',destinationUrl:'',slug:'',status:'draft',ocrEnabled:true,ocrReferenceTexts:[],ocrApprovalThreshold:58,ocrMinSpecificMatches:2,ocrMaxAttempts:6,referenceImageUrl:'',referenceImagePath:'',referenceOcrText:''}}
function newCampaign(){state.editor=blankCampaign();state.pendingCover=null;state.pendingThumb=null;state.pendingChannelLogo=null;state.pendingReference=null;renderEditor()}
async function editCampaign(id){
  const c=state.campaigns.find(x=>x.id===id);if(!c)return;
  showLoading();
  try{
    const privateSnap=await getDoc(doc(db,'campaignPrivate',id));
    state.editor={...blankCampaign(),...structuredClone(c),...(privateSnap.exists()?privateSnap.data():{})};
    state.pendingCover=null;state.pendingThumb=null;state.pendingChannelLogo=null;state.pendingReference=null;renderEditor();
  }catch(e){console.error(e);toast('No se pudo abrir la configuración privada.');goAdmin()}
}
function renderEditor(){
  setView('editor');const c=state.editor;
  $('#view-editor').innerHTML=`<div class="editor-layout"><div class="editor-card"><div class="editor-header"><div><span class="kicker">Constructor conectado</span><h1 class="title">${c.title?'Editar enlace':'Crear nuevo enlace'}</h1><p>Configura el contenido, la referencia y el enlace público.</p></div><button class="btn btn-secondary btn-sm" onclick="App.goAdmin()">${icon('arrowLeft','icon-sm')}Volver</button></div><div class="editor-body">
  <section class="editor-section"><h3>1. Contenido que se entregará</h3><p>Información principal de la campaña.</p><div class="form-grid"><div class="field"><label class="field-label">Título</label><input class="input" id="edTitle" value="${attr(c.title)}"></div><div class="field"><label class="field-label">Tipo</label><select class="select" id="edType">${['video','apk','software','file','link','other'].map(t=>`<option value="${t}" ${c.contentType===t?'selected':''}>${typeLabel(t)}</option>`).join('')}</select></div></div><div class="field"><label class="field-label">Descripción</label><textarea class="textarea" id="edDesc">${esc(c.description)}</textarea></div><div class="field"><span class="field-label">Formato de portada</span><div class="format-grid" id="formatGrid">${[['horizontal','monitor','Horizontal 16:9'],['square','square','Cuadrada 1:1'],['vertical','user','Vertical']].map(([v,i,l])=>`<button type="button" class="format-btn ${c.format===v?'active':''}" data-format="${v}">${icon(i)}${l}</button>`).join('')}</div></div><div class="file-box"><img class="preview-image ${c.coverUrl?'':'hidden'}" id="coverPreview" src="${attr(c.coverUrl)}" alt="Portada"><label class="upload-box" for="coverInput">${icon('upload')}<div><strong>Seleccionar o cambiar portada</strong><div class="field-hint">JPG, PNG o WebP. Máximo 3 MB.</div></div></label><input class="hidden" id="coverInput" type="file" accept="image/jpeg,image/png,image/webp"></div><div class="field" style="margin-top:14px"><label class="field-label">Enlace final protegido</label><input class="input" id="edDestination" value="${attr(c.destinationUrl)}" placeholder="https://..."><div class="field-hint">Se guarda en la zona privada y solo se entrega después de aprobar la captura.</div></div></section>
  <section class="editor-section"><h3>2. Video de referencia</h3><p>Puedes pegar el enlace de YouTube o subir una miniatura manual.</p><div class="field"><label class="field-label">Enlace del video de YouTube (opcional)</label><input class="input" id="edVideoUrl" value="${attr(c.videoUrl||'')}" placeholder="https://www.youtube.com/watch?v=..."><div class="field-hint">Se usa para obtener la miniatura automáticamente. En la página pública no se muestra como enlace clicable.</div></div><div class="form-grid"><div class="field"><label class="field-label">Título del video</label><input class="input" id="edVideoTitle" value="${attr(c.videoTitle)}"></div><div class="field"><label class="field-label">Canal</label><input class="input" id="edChannel" value="${attr(c.channel)}"></div></div><div class="channel-logo-editor ${c.channelLogoUrl?'has-logo':''}" id="channelLogoEditor"><img class="channel-logo-preview ${c.channelLogoUrl?'':'hidden'}" id="channelLogoPreview" src="${attr(c.channelLogoUrl||'')}" alt="Logo del canal"><label class="upload-box channel-logo-upload" for="channelLogoInput">${icon('user')}<div><strong>Subir logo del canal</strong><div class="field-hint">Opcional. Se mostrará junto al nombre del canal para facilitar la búsqueda.</div></div></label><input class="hidden" id="channelLogoInput" type="file" accept="image/jpeg,image/png,image/webp"></div><div class="field"><label class="field-label">Frase que copiará el usuario</label><input class="input" id="edKeyword" value="${attr(c.keyword)}"></div><div class="form-grid"><div class="field"><label class="field-label">Tiempo orientativo</label><select class="select" id="edWatch">${[30,45,60].map(n=>`<option value="${n}" ${Number(c.watchSeconds)===n?'selected':''}>${n} segundos</option>`).join('')}</select></div><div class="field"><label class="field-label">Captura</label><select class="select" id="edScreenshot"><option value="required" ${c.screenshotRequired?'selected':''}>Obligatoria</option><option value="optional" ${!c.screenshotRequired?'selected':''}>Opcional</option></select></div></div><div class="file-box"><img class="preview-image ${c.videoThumbUrl?'':'hidden'}" id="thumbPreview" src="${attr(c.videoThumbUrl)}" alt="Miniatura"><label class="upload-box" for="thumbInput">${icon('image')}<div><strong>Subir miniatura manual</strong><div class="field-hint">Si no subes una, se usará la miniatura de YouTube.</div></div></label><input class="hidden" id="thumbInput" type="file" accept="image/jpeg,image/png,image/webp"></div></section>
  <section class="editor-section validation-section"><div class="validation-heading"><div><h3>3. Validación automática de captura</h3><p>El sistema leerá el texto visible y comprobará que corresponda a este video.</p></div><label class="switch-line"><input id="edOcrEnabled" type="checkbox" ${c.ocrEnabled!==false?'checked':''}><span>Activada</span></label></div><div class="validation-note">${icon('shield','icon-sm')}El título y el canal se usan automáticamente. Agrega únicamente frases específicas que también puedan verse en la captura.</div><div class="field"><label class="field-label">Frases específicas adicionales</label><textarea class="textarea" id="edOcrRefs" style="min-height:125px" placeholder="Ejemplo: demostración real paso a paso">${esc((c.ocrReferenceTexts||[]).join('\n'))}</textarea><div class="field-hint">Usa frases de 2 o más palabras. Evita palabras sueltas como “seguidores”, “video”, “YouTube” o “Instagram”.</div></div><div class="form-grid validation-grid"><div class="field"><label class="field-label">Nivel mínimo para aprobar</label><input class="input" id="edOcrThreshold" type="number" min="40" max="90" step="1" value="${Number(c.ocrApprovalThreshold)||58}"><div class="field-hint">Recomendado: 58</div></div><div class="field"><label class="field-label">Palabras específicas mínimas</label><input class="input" id="edOcrMinMatches" type="number" min="1" max="6" step="1" value="${Number(c.ocrMinSpecificMatches)||2}"><div class="field-hint">Recomendado: 2</div></div><div class="field"><label class="field-label">Intentos máximos cada 24 horas</label><input class="input" id="edOcrMaxAttempts" type="number" min="1" max="12" step="1" value="${Number(c.ocrMaxAttempts)||6}"></div></div><div class="file-box"><img class="preview-image ${c.referenceImageUrl?'':'hidden'}" id="referencePreview" src="${attr(c.referenceImageUrl||'')}" alt="Captura de referencia"><label class="upload-box" for="referenceInput">${icon('camera')}<div><strong>Subir una captura correcta de referencia</strong><div class="field-hint">Opcional. El OCR extraerá más texto útil automáticamente.</div></div></label><input class="hidden" id="referenceInput" type="file" accept="image/jpeg,image/png,image/webp"></div></section>
  <section class="editor-section"><h3>4. Banco de ideas de comentarios</h3><p>Escribe una idea por línea. Cada visita mostrará tres opciones diferentes.</p><div class="comment-bank-meta"><span>Para que los tres cambien al recargar, guarda al menos 6 comentarios.</span><strong id="promptCount">${Math.min((c.commentPrompts||[]).length,200)} / 200</strong></div><textarea class="textarea" id="edPrompts" style="min-height:240px">${esc((c.commentPrompts||[]).join('\n'))}</textarea><div class="field-hint">Las ideas deben ser variadas, relacionadas con el video y fáciles de personalizar. Máximo 200.</div></section>
  <section class="editor-section"><h3>5. Widget publicitario opcional</h3><p>Pega aquí el HTML del anuncio. Se mostrará dentro de un marco aislado y también en la vista previa.</p><textarea class="textarea" id="edAdHtml" style="min-height:130px" placeholder="<script>...<\/script>">${esc(c.adHtml||'')}</textarea></section>
  <section class="editor-section"><h3>6. Enlace público</h3><div class="field"><label class="field-label">Nombre del enlace</label><input class="input" id="edSlug" value="${attr(c.slug)}" placeholder="video-completo"><div class="field-hint" id="slugPreview">${esc(state.settings.domain)}${esc(c.slug||'nombre-del-enlace')}</div></div><div class="check-row"><input id="edStatus" type="checkbox" ${c.status==='active'?'checked':''}><label for="edStatus">Publicar inmediatamente<small>Desmárcalo para guardarlo como borrador.</small></label></div></section></div><div class="editor-footer"><button class="btn btn-secondary" onclick="App.goAdmin()">Cancelar</button><button class="btn btn-primary" id="saveBtn" onclick="App.saveCampaign()">${icon('check')}Guardar enlace</button></div></div><aside><div class="phone"><div class="phone-screen" id="phonePreview"></div></div></aside></div>`;
  bindEditor();updateEditorFromForm();
}
function bindEditor(){
  ['edTitle','edType','edDesc','edDestination','edVideoUrl','edVideoTitle','edChannel','edKeyword','edWatch','edScreenshot','edPrompts','edAdHtml','edSlug','edStatus','edOcrEnabled','edOcrRefs','edOcrThreshold','edOcrMinMatches','edOcrMaxAttempts'].forEach(id=>{const el=$('#'+id);if(el)el.addEventListener(['edType','edWatch','edScreenshot','edStatus','edOcrEnabled'].includes(id)?'change':'input',updateEditorFromForm)});
  $$('#formatGrid .format-btn').forEach(b=>b.onclick=()=>{$$('#formatGrid .format-btn').forEach(x=>x.classList.toggle('active',x===b));state.editor.format=b.dataset.format;renderPhonePreview()});
  $('#coverInput').onchange=e=>selectImage(e,'cover');$('#thumbInput').onchange=e=>selectImage(e,'thumb');$('#channelLogoInput').onchange=e=>selectImage(e,'channelLogo');$('#referenceInput').onchange=e=>selectImage(e,'reference');updatePromptCount();
}
function selectImage(e,kind){
  const f=e.target.files[0];if(!f)return;
  const max=kind==='reference'?5:3;
  if(!['image/jpeg','image/png','image/webp'].includes(f.type)||f.size>max*1024*1024){toast(`Selecciona una imagen JPG, PNG o WebP de menos de ${max} MB.`);return}
  const url=URL.createObjectURL(f);
  if(kind==='cover'){state.pendingCover=f;state.editor.coverUrl=url;$('#coverPreview').src=url;$('#coverPreview').classList.remove('hidden')}
  else if(kind==='thumb'){state.pendingThumb=f;state.editor.videoThumbUrl=url;$('#thumbPreview').src=url;$('#thumbPreview').classList.remove('hidden')}
  else if(kind==='channelLogo'){state.pendingChannelLogo=f;state.editor.channelLogoUrl=url;$('#channelLogoPreview').src=url;$('#channelLogoPreview').classList.remove('hidden');$('#channelLogoEditor')?.classList.add('has-logo')}
  else{state.pendingReference=f;state.editor.referenceImageUrl=url;$('#referencePreview').src=url;$('#referencePreview').classList.remove('hidden')}
  renderPhonePreview();
}
function updatePromptCount(){const el=$('#edPrompts'),counter=$('#promptCount');if(!el||!counter)return;const count=el.value.split('\n').map(x=>x.trim()).filter(Boolean).length;counter.textContent=`${Math.min(count,200)} / 200`;counter.classList.toggle('limit',count>200)}
function updateEditorFromForm(){
  const c=state.editor;c.title=$('#edTitle')?.value||'';c.contentType=$('#edType')?.value||'video';c.description=$('#edDesc')?.value||'';c.destinationUrl=$('#edDestination')?.value||'';c.videoUrl=$('#edVideoUrl')?.value||'';c.videoTitle=$('#edVideoTitle')?.value||'';c.channel=$('#edChannel')?.value||'';c.keyword=$('#edKeyword')?.value||'';c.watchSeconds=Number($('#edWatch')?.value||30);c.screenshotRequired=$('#edScreenshot')?.value==='required';c.commentPrompts=($('#edPrompts')?.value||'').split('\n').map(x=>x.trim()).filter(Boolean).slice(0,200);updatePromptCount();c.adHtml=$('#edAdHtml')?.value||'';c.slug=slugify($('#edSlug')?.value||'');c.status=$('#edStatus')?.checked?'active':'draft';c.ocrEnabled=$('#edOcrEnabled')?.checked!==false;c.ocrReferenceTexts=($('#edOcrRefs')?.value||'').split('\n').map(x=>x.trim()).filter(x=>x.split(/\s+/).length>=2).slice(0,20);c.ocrApprovalThreshold=Math.min(90,Math.max(40,Number($('#edOcrThreshold')?.value||58)));c.ocrMinSpecificMatches=Math.min(6,Math.max(1,Number($('#edOcrMinMatches')?.value||2)));c.ocrMaxAttempts=Math.min(12,Math.max(1,Number($('#edOcrMaxAttempts')?.value||6)));
  if($('#edSlug')&&$('#edSlug').value!==c.slug)$('#edSlug').value=c.slug;if($('#slugPreview'))$('#slugPreview').textContent=state.settings.domain+(c.slug||'nombre-del-enlace')+'/';if(c.videoUrl&&!state.pendingThumb){const y=youtubeThumb(c.videoUrl);if(y){c.videoThumbUrl=y;$('#thumbPreview').src=y;$('#thumbPreview').classList.remove('hidden')}}renderPhonePreview();
}
function youtubeId(url=''){try{const u=new URL(url);if(u.hostname.includes('youtu.be'))return u.pathname.slice(1).split('/')[0];if(u.searchParams.get('v'))return u.searchParams.get('v');const m=u.pathname.match(/\/(shorts|embed)\/([^/?]+)/);return m?.[2]||''}catch{return''}}
function youtubeThumb(url){const id=youtubeId(url);return id?`https://i.ytimg.com/vi/${id}/hqdefault.jpg`:''}
function channelMarkup(c,mode='reference'){
  const name=esc(c.channel||'');const logo=c.channelLogoUrl?attr(c.channelLogoUrl):'';
  if(mode==='guide')return logo?`<small class="guide-channel"><img src="${logo}" alt="">${name} · Video</small>`:`<small>${name} · Video</small>`;
  return logo?`<span class="channel-line"><img class="channel-logo" src="${logo}" alt="Logo del canal"><span>Canal: ${name}</span></span>`:`<span>Canal: ${name}</span>`;
}
function renderPhonePreview(){if(!$('#phonePreview'))return;$('#phonePreview').innerHTML=publicMarkup(state.editor,true);hydrateAdFrames($('#phonePreview'))}
async function uploadImage(file,path){const r=ref(storage,path);await uploadBytes(r,file,{contentType:file.type});return getDownloadURL(r)}
async function saveCampaign(){
  updateEditorFromForm();const c=state.editor;
  if(!c.title||!c.description||!c.destinationUrl||!c.slug||!c.keyword||!c.videoTitle||!c.channel){toast('Completa todos los campos principales.');return}
  if(!c.coverUrl&&!state.pendingCover){toast('Selecciona una portada.');return}
  const btn=$('#saveBtn');btn.disabled=true;btn.textContent='Guardando…';
  try{
    if(state.pendingCover)c.coverUrl=await uploadImage(state.pendingCover,`campaign-covers/${c.id}/cover-${Date.now()}.${extFor(state.pendingCover)}`);
    if(state.pendingThumb)c.videoThumbUrl=await uploadImage(state.pendingThumb,`campaign-thumbnails/${c.id}/thumb-${Date.now()}.${extFor(state.pendingThumb)}`);
    if(state.pendingChannelLogo)c.channelLogoUrl=await uploadImage(state.pendingChannelLogo,`campaign-thumbnails/${c.id}/channel-logo-${Date.now()}.${extFor(state.pendingChannelLogo)}`);
    if(state.pendingReference){c.referenceImagePath=`campaign-validation-references/${c.id}/reference-${Date.now()}.${extFor(state.pendingReference)}`;c.referenceImageUrl=await uploadImage(state.pendingReference,c.referenceImagePath)}
    if(!c.videoThumbUrl)c.videoThumbUrl=youtubeThumb(c.videoUrl)||c.coverUrl;
    const now=serverTimestamp();
    const publicData={title:c.title,description:c.description,contentType:c.contentType,format:c.format,coverUrl:c.coverUrl,videoThumbUrl:c.videoThumbUrl,videoUrl:c.videoUrl,videoTitle:c.videoTitle,channel:c.channel,channelLogoUrl:c.channelLogoUrl||'',keyword:c.keyword,watchSeconds:c.watchSeconds,screenshotRequired:c.screenshotRequired,commentPrompts:c.commentPrompts,adHtml:c.adHtml,slug:c.slug,status:c.status,createdAt:c.createdAt||now,updatedAt:now};
    const alreadyExists=state.campaigns.some(item=>item.id===c.id);
    if(alreadyExists)Object.assign(publicData,{destinationUrl:deleteField(),ocrEnabled:deleteField(),ocrReferenceTexts:deleteField(),ocrApprovalThreshold:deleteField(),ocrMinSpecificMatches:deleteField(),ocrMaxAttempts:deleteField(),referenceImageUrl:deleteField(),referenceImagePath:deleteField(),referenceOcrText:deleteField()});
    const privateData={destinationUrl:c.destinationUrl,ocrEnabled:c.ocrEnabled!==false,ocrReferenceTexts:c.ocrReferenceTexts||[],ocrApprovalThreshold:c.ocrApprovalThreshold||58,ocrMinSpecificMatches:c.ocrMinSpecificMatches||2,ocrMaxAttempts:c.ocrMaxAttempts||6,referenceImageUrl:c.referenceImageUrl||'',referenceImagePath:c.referenceImagePath||'',referenceOcrText:c.referenceOcrText||'',updatedAt:now};
    await Promise.all([setDoc(doc(db,'campaigns',c.id),publicData,{merge:true}),setDoc(doc(db,'campaignPrivate',c.id),privateData,{merge:true})]);
    if(state.pendingReference&&c.referenceImagePath){btn.textContent='Leyendo referencia…';try{await analyzeReferenceImageFn({campaignId:c.id,screenshotPath:c.referenceImagePath})}catch(err){console.warn('reference OCR',err);toast('El enlace se guardó, pero la captura de referencia no pudo analizarse todavía.')}}
    state.pendingCover=null;state.pendingThumb=null;state.pendingChannelLogo=null;state.pendingReference=null;toast('Enlace guardado correctamente.');await loadAdminData();
  }catch(e){console.error(e);toast('No se pudo guardar: '+(e.message||e.code))}finally{btn.disabled=false}
}
function extFor(f){return f.type==='image/png'?'png':f.type==='image/webp'?'webp':'jpg'}
async function removeCampaign(id){if(!confirm('¿Eliminar esta campaña?'))return;try{await Promise.all([deleteDoc(doc(db,'campaigns',id)),deleteDoc(doc(db,'campaignPrivate',id))]);toast('Campaña eliminada.');loadAdminData()}catch(e){toast('No se pudo eliminar.') }}
function copyLink(id){const c=state.campaigns.find(x=>x.id===id);copyText(publicUrl(c),'Enlace público copiado.')}
function openPublic(slug){location.href=state.settings.domain.replace(/\/+$/,'/')+encodeURIComponent(slug)+'/' }

async function migrateLocal(){
  const raw=localStorage.getItem('vidpase_access_v1');if(!raw){toast('No hay campañas locales para migrar.');return}
  let list=[];try{list=JSON.parse(raw)||[]}catch{toast('No se pudieron leer los datos locales.');return}
  if(!list.length){toast('No hay campañas locales.');return}if(!confirm(`Se migrarán ${list.length} campañas a Firebase. ¿Continuar?`))return;showLoading();
  for(const old of list){
    try{
      const c={...blankCampaign(),...old,coverUrl:old.coverUrl||'',videoThumbUrl:old.videoThumbUrl||'',destinationUrl:old.destinationUrl||''};
      if(old.cover?.startsWith('data:'))c.coverUrl=await uploadImage(dataUrlFile(old.cover,'cover.png'),`campaign-covers/${c.id}/cover-migrated.png`);else c.coverUrl=old.cover||c.coverUrl;
      if(old.videoThumb?.startsWith('data:'))c.videoThumbUrl=await uploadImage(dataUrlFile(old.videoThumb,'thumb.png'),`campaign-thumbnails/${c.id}/thumb-migrated.png`);else c.videoThumbUrl=old.videoThumb||c.videoThumbUrl||c.coverUrl;
      const now=serverTimestamp();
      const publicData={title:c.title,description:c.description,contentType:c.contentType,format:c.format,coverUrl:c.coverUrl,videoThumbUrl:c.videoThumbUrl,videoUrl:c.videoUrl||'',videoTitle:c.videoTitle,channel:c.channel,channelLogoUrl:c.channelLogoUrl||'',keyword:c.keyword,watchSeconds:c.watchSeconds,screenshotRequired:c.screenshotRequired,commentPrompts:c.commentPrompts||[],adHtml:c.adHtml||'',slug:c.slug,status:c.status||'draft',createdAt:now,updatedAt:now};
      const privateData={destinationUrl:c.destinationUrl||'',ocrEnabled:c.ocrEnabled!==false,ocrReferenceTexts:c.ocrReferenceTexts||[],ocrApprovalThreshold:c.ocrApprovalThreshold||58,ocrMinSpecificMatches:c.ocrMinSpecificMatches||2,ocrMaxAttempts:c.ocrMaxAttempts||6,updatedAt:now};
      await Promise.all([setDoc(doc(db,'campaigns',c.id),publicData),setDoc(doc(db,'campaignPrivate',c.id),privateData)]);
    }catch(e){console.error('migrate',e)}
  }
  toast('Migración terminada.');loadAdminData()
}
function dataUrlFile(dataUrl,name){const [h,b]=dataUrl.split(',');const mime=h.match(/:(.*?);/)?.[1]||'image/png';const bin=atob(b);const arr=new Uint8Array(bin.length);for(let i=0;i<bin.length;i++)arr[i]=bin.charCodeAt(i);return new File([arr],name,{type:mime})}

function renderSettings(){showModal(`<h3>Configuración general</h3><div class="field"><label class="field-label">Nombre del proyecto</label><input class="input" id="setBrand" value="${attr(state.settings.brand)}"></div><div class="field"><label class="field-label">Dominio</label><input class="input" id="setDomain" value="${attr(state.settings.domain)}"></div><div class="security-tool"><strong>Protección de enlaces antiguos</strong><p>Mueve los enlaces finales que todavía estén en datos públicos hacia la zona privada.</p><button class="btn btn-secondary btn-wide" onclick="App.secureLegacyCampaigns()">${icon('shield')}Proteger campañas existentes</button></div><div class="modal-actions"><button class="btn btn-secondary" onclick="App.closeModal()">Cancelar</button><button class="btn btn-primary" onclick="App.saveSettings()">Guardar</button></div>`)}
async function saveSettings(){const brand=$('#setBrand').value.trim()||'VidPase';let domain=$('#setDomain').value.trim()||'https://vidpase.github.io/';if(!domain.endsWith('/'))domain+='/';await setDoc(doc(db,'siteSettings','global'),{brand,domain,updatedAt:serverTimestamp()},{merge:true});state.settings={brand,domain};closeModal();toast('Configuración guardada.');renderAdmin()}

async function showSubmissions(){
  setView('submissions');
  const statusLabel=s=>({approved:'Aprobada',rejected:'Rechazada',processing:'Procesando'}[s]||'Registrada');
  $('#view-submissions').innerHTML=`<div class="admin-hero"><div><span class="kicker">Actividad recibida</span><h1 class="title">Capturas enviadas</h1><p>Consulta el resultado del OCR y corrige una decisión cuando sea necesario.</p></div><button class="btn btn-secondary" onclick="App.goAdmin()">${icon('arrowLeft')}Volver</button></div>${state.submissions.length?`<div class="submissions-list">${state.submissions.map(s=>{const c=state.campaigns.find(x=>x.id===s.campaignId);const v=s.validation||{};return `<article class="submission validation-submission"><div><div class="submission-title-row"><h3>${esc(c?.title||s.campaignId)}</h3><span class="status ${s.status==='approved'?'live':s.status==='rejected'?'rejected':'draft'}">${statusLabel(s.status)}</span></div><p>Usuario: ${esc(s.ownerUid||'')}</p><div class="validation-summary"><span><b>Coincidencia:</b> ${Number.isFinite(v.matchScore)?Math.round(v.matchScore)+'%':'Sin resultado'}</span><span><b>Motivo:</b> ${esc(v.reasonLabel||'Todavía no disponible')}</span></div>${v.ocrText?`<details><summary>Texto detectado por OCR</summary><pre>${esc(v.ocrText)}</pre></details>`:''}</div><div class="submission-actions"><button class="btn btn-soft btn-sm" onclick="App.viewScreenshot('${s.id}')">${icon('image','icon-sm')}Ver captura</button><button class="btn btn-success btn-sm" onclick="App.moderateSubmission('${s.id}','approved')">${icon('check','icon-sm')}Aprobar</button><button class="btn btn-danger btn-sm" onclick="App.moderateSubmission('${s.id}','rejected')">${icon('trash','icon-sm')}Rechazar</button></div></article>`}).join('')}</div>`:`<div class="card empty"><h3>Todavía no hay capturas</h3><p>Cuando un visitante complete una campaña, aparecerá aquí.</p></div>`}`
}
async function viewScreenshot(id){
  const s=state.submissions.find(x=>x.id===id);if(!s?.screenshotPath){toast('Este registro no tiene captura.');return}
  try{const url=await getDownloadURL(ref(storage,s.screenshotPath));const v=s.validation||{};showModal(`<h3>Captura enviada</h3><img class="modal-image" src="${attr(url)}" alt="Captura"><div class="modal-validation"><p><strong>Estado:</strong> ${esc(s.status||'')}</p><p><strong>Coincidencia:</strong> ${Number.isFinite(v.matchScore)?Math.round(v.matchScore)+'%':'Sin resultado'}</p><p><strong>Motivo:</strong> ${esc(v.reasonLabel||'Sin información')}</p>${v.ocrText?`<div><strong>Texto detectado:</strong><pre>${esc(v.ocrText)}</pre></div>`:''}</div><div class="modal-actions"><button class="btn btn-danger" onclick="App.moderateSubmission('${s.id}','rejected')">Rechazar</button><button class="btn btn-success" onclick="App.moderateSubmission('${s.id}','approved')">Aprobar</button><button class="btn btn-secondary" onclick="App.closeModal()">Cerrar</button></div>`)}catch(e){toast('No se pudo abrir la captura.')}
}
async function moderateSubmission(id,status){
  try{await moderateSubmissionFn({submissionId:id,status});closeModal();toast(status==='approved'?'Captura aprobada.':'Captura rechazada.');await loadAdminData();showSubmissions()}catch(e){console.error(e);toast('No se pudo cambiar el estado.')}
}
async function secureLegacyCampaigns(){
  const btn=document.activeElement instanceof HTMLButtonElement?document.activeElement:null;if(btn){btn.disabled=true;btn.textContent='Protegiendo…'}
  try{const r=await secureLegacyCampaignsFn({});toast(`${r.data.updated||0} campañas protegidas.`);closeModal();await loadAdminData()}catch(e){console.error(e);toast('No se pudo completar la protección.')}finally{if(btn)btn.disabled=false}
}

async function loadPublic(slug){showLoading();try{await ensureAnonymous();const q=query(collection(db,'campaigns'),where('slug','==',slug),where('status','==','active'),limit(1));const snap=await getDocs(q);if(snap.empty){renderNotFound();return}state.publicCampaign=snapshotData(snap.docs[0]);state.publicStage='intro';if(state.public.guideTimer)clearTimeout(state.public.guideTimer);state.public={youtubeOpened:false,watched:false,screenshotFile:null,screenshotData:'',uploading:false,finalYoutubeOpened:false,finalReturned:false,awaitingFinalReturn:false,guideVisible:false,guideTimer:null,promptIds:selectPromptIds(state.publicCampaign),submissionId:'',unlockedUrl:'',retrying:false};renderPublic();const key=`vp-view-${state.publicCampaign.id}`;if(!sessionStorage.getItem(key)){sessionStorage.setItem(key,'1');logEvent('page_view',state.publicCampaign.id)}}catch(e){console.error(e);renderNotFound('No se pudo cargar la campaña.')}}
function renderNotFound(msg='Este enlace no está disponible.'){document.body.classList.remove('wizard-open');setView('public');$('#view-public').innerHTML=`<div class="public-home"><div class="card empty"><h3>${esc(msg)}</h3><p>Comprueba el enlace o inténtalo más tarde.</p></div></div>`}
function renderPublic(){setView('public');document.title=`${state.publicCampaign.title} — ${state.settings.brand}`;document.body.classList.toggle('wizard-open',state.publicStage!=='intro');$('#view-public').innerHTML=publicMarkup(state.publicCampaign,false);hydrateAdFrames($('#view-public'));bindPublic()}
function trustMarkup(){return `<div class="promise-row-v3"><div class="promise-v3"><span>${icon('check','icon-sm')}</span>Sin registro</div><div class="promise-v3"><span>${icon('check','icon-sm')}</span>Proceso guiado</div><div class="promise-v3"><span>${icon('check','icon-sm')}</span>Enlace directo</div></div>`}
function publicMarkup(c,preview){if(preview)return previewPublicMarkup(c);return `<div class="public-experience"><div class="public-home">${publicHeroMarkup(c)}${c.adHtml?`<div class="public-ad-v3"><div class="ad-slot"><div class="ad-slot-label">Espacio publicitario</div><iframe class="ad-frame" data-ad-frame></iframe></div></div>`:''}${howMarkup()}</div>${state.publicStage!=='intro'?wizardMarkup(c):''}</div>`}
function previewPublicMarkup(c){return `<article class="preview-public-v3"><img src="${attr(c.coverUrl||'')}" alt="${attr(c.title||'Portada')}"><div class="preview-public-body-v3"><span class="kicker">Contenido que recibirá el usuario</span><h3>${esc(c.title||'Título del contenido')}</h3><p>${esc(c.description||'Descripción del contenido.')}</p><button class="btn btn-primary btn-wide" disabled>Comenzar ahora${icon('arrow')}</button></div></article>`}
function publicHeroMarkup(c){return `<section class="public-hero"><div class="hero-copy-v3"><span class="eyebrow-v3">${icon('checkCircle','icon-sm')}Contenido gratuito</span><h1 class="hero-title-v3">Tu enlace está a solo 3 pasos.</h1><p class="hero-text-v3">No necesitas registrarte ni navegar por páginas confusas. Te mostraremos una sola instrucción a la vez hasta entregarte el contenido.</p>${trustMarkup()}<button class="btn btn-primary hero-start" onclick="App.publicStart()">Comenzar ahora${icon('arrow')}</button><div class="mini-note-v3">${icon('shield','icon-sm')}Las acciones como comentar o suscribirse son opcionales.</div></div><div class="public-resource-card"><div class="card-glow-v3"></div><article class="resource-frame-v3"><div class="resource-cover-v3"><img src="${attr(c.coverUrl||'')}" alt="${attr(c.title)}"><div class="cover-shade-v3"></div><div class="play-orb-v3">${icon(typeIcon(c.contentType),'icon-lg')}</div><div class="cover-copy-v3"><span class="cover-kicker-v3">Recurso disponible</span><div class="cover-title-v3">${esc(c.title||'Contenido exclusivo')}</div></div></div><div class="resource-body-v3"><div class="resource-meta-v3"><span class="resource-type-v3">${icon(typeIcon(c.contentType),'icon-sm')}${esc(typeLabel(c.contentType))}</span><span class="time-badge-v3">2–3 minutos</span></div><h2>Lo que recibirás al finalizar</h2><p>${esc(c.description||'Acceso inmediato al contenido completo, sin anuncios invasivos ni redirecciones innecesarias.')}</p></div></article></div></section>`}
function resourceMarkup(c,preview){return preview?previewPublicMarkup(c):publicHeroMarkup(c)}
function howMarkup(){return `<section class="how-v3"><div class="how-head-v3"><span>Así funciona</span><h2>Una tarea clara en cada pantalla</h2><p>Nunca tendrás que descubrir por tu cuenta qué hacer después.</p></div><div class="steps-preview-v3"><article class="preview-step-v3"><b>1</b><strong>Copia y busca</strong><p>Te damos exactamente el texto que debes colocar en YouTube.</p></article><article class="preview-step-v3"><b>2</b><strong>Encuentra el video</strong><p>Compara una sola miniatura, el título y el canal.</p></article><article class="preview-step-v3"><b>3</b><strong>Sube una captura</strong><p>El sistema la revisa y te entrega el enlace final.</p></article></div></section>`}
function stageMeta(){return {search:['Paso 1 · Buscar','1 de 3',18],identify:['Paso 2 · Encontrar','2 de 3',52],participate:['Paso 3 · Captura','3 de 3',86],review:['Verificación','Revisando',100],unlocked:['Completado','Listo',100]}[state.publicStage]||['Proceso','',0]}
function wizardMarkup(c){const [label,count,width]=stageMeta();const closable=state.publicStage!=='review';return `<div class="wizard-layer-v3" id="journey"><section class="wizard-v3" role="dialog" aria-modal="true" aria-labelledby="wizardTitle"><div class="wizard-top-v3"><div class="wizard-head-v3"><div class="wizard-brand-v3"><span class="brand-mark">${icon('link')}</span>${esc(state.settings.brand)}</div>${closable?`<button class="wizard-close-v3" type="button" aria-label="Cerrar" onclick="App.closePublicWizard()">${icon('close','icon-sm')}</button>`:''}</div><div class="progress-wrap-v3"><span class="step-label-v3">${esc(label)}</span><div class="progress-track-v3"><div class="progress-fill-v3" style="width:${width}%"></div></div><span class="step-count-v3">${esc(count)}</span></div></div><div class="wizard-body-v3">${journeyMarkup(c)}</div></section></div>`}
function journeyMarkup(c){if(state.publicStage==='search')return searchStage(c);if(state.publicStage==='identify')return identifyStage(c);if(state.publicStage==='participate')return participateStage(c);if(state.publicStage==='review')return reviewStage();return unlockedStage(c)}
function shell(title,step,w,body){return `<section class="wizard-stage-v3"><div class="stage-shell-v3">${body}</div></section>`}
function shuffleIds(ids){const copy=[...ids];for(let i=copy.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[copy[i],copy[j]]=[copy[j],copy[i]]}return copy}
function selectPromptIds(c){const bank=(c.commentPrompts||[]).filter(Boolean).slice(0,200);if(!bank.length)return[];const key=`vp-last-prompts-${c.id}`;let previous=[];try{const saved=JSON.parse(sessionStorage.getItem(key)||'[]');if(Array.isArray(saved))previous=saved.filter(i=>Number.isInteger(i)&&i>=0&&i<bank.length)}catch{}const all=[...bank.keys()];const fresh=shuffleIds(all.filter(i=>!previous.includes(i)));const fallback=shuffleIds(all.filter(i=>!fresh.includes(i)));const ids=[...fresh,...fallback].slice(0,Math.min(3,bank.length));try{sessionStorage.setItem(key,JSON.stringify(ids))}catch{}return ids}
function randomPrompts(c){const bank=(c.commentPrompts||[]).filter(Boolean).slice(0,200);if(!Array.isArray(state.public.promptIds)||!state.public.promptIds.length)state.public.promptIds=selectPromptIds(c);return state.public.promptIds.map(i=>bank[i]).filter(Boolean)}
function searchStage(c){const copied=state.public.guideVisible;return shell('Copia el texto','Paso 1',18,`<div class="v3-stage-icon">${icon('search','icon-lg')}</div><h2 class="stage-title-v3" id="wizardTitle">Primero, copia este texto</h2><p class="stage-subtitle-v3">Es el texto exacto que debes pegar en el buscador de YouTube. No necesitas escribir nada.</p><div class="instruction-card-v3"><div class="instruction-kicker-v3"><span>1</span>Texto de búsqueda</div><div class="keyword-v3"><div class="keyword-text-v3">${esc(c.keyword)}</div><button class="copy-btn-v3 ${copied?'copied':''}" type="button" onclick="App.copyKeyword()">${icon(copied?'check':'copy','icon-sm')}<span>${copied?'Copiado':'Copiar'}</span></button></div><div class="micro-help-v3">${icon('shield','icon-sm')}Al copiarlo, verás exactamente qué video debes encontrar.</div></div>${copied?youtubeGuideMarkup(c):youtubeGuideWaitingMarkup()}<button class="btn btn-primary btn-wide stage-action-v3" ${copied?'':'disabled'} onclick="App.goFindVideo()">Continuar al paso 2${icon('arrow')}</button>`) }
function identifyStage(c){const prompts=randomPrompts(c);return shell('Encuentra el video','Paso 2',52,`<div class="v3-stage-icon">${icon('youtube','icon-lg')}</div><h2 class="stage-title-v3" id="wizardTitle">Ahora encuentra este video</h2><p class="stage-subtitle-v3">Compara únicamente la miniatura, el título y el canal. Cuando coincidan, habrás encontrado el video correcto.</p><div class="video-match-v3"><div class="video-thumb-v3"><img src="${attr(c.videoThumbUrl||c.coverUrl)}" alt="Miniatura del video correcto"></div><div class="video-copy-v3"><small>Este es el video correcto</small><strong>${esc(c.videoTitle)}</strong>${channelMarkup(c)}</div></div><div class="find-checks-v3 youtube-actions-visible-v3"><div class="find-check-v3">${icon('checkCircle','icon-sm')}La miniatura debe ser la misma.</div><div class="find-check-v3">${icon('checkCircle','icon-sm')}El título y el canal deben coincidir.</div><div class="find-check-v3">${icon('play','icon-sm')}Reproduce el video durante más de ${Number(c.watchSeconds)||30} segundos.</div><div class="find-check-v3 action-comment-v3">${icon('message','icon-sm')}<div><strong>Puedes dejar un comentario relacionado</strong><small>Es opcional. Usa una idea de abajo y ajústala a lo que realmente piensas.</small></div><span class="optional-badge-v3">Opcional</span></div>${prompts.length?`<div class="comment-list-inline-v3"><div class="comment-list-head-v3"><strong>Ideas de comentarios</strong><span>Elige uno y personalízalo</span></div>${prompts.map((p,i)=>`<div class="comment-option-v3"><span>${esc(p)}</span><button type="button" onclick="App.copyOptionalComment(${i})">${icon('copy','icon-sm')}Copiar</button></div>`).join('')}</div>`:''}<div class="find-check-v3">${icon('thumbsUp','icon-sm')}<div><strong>Puedes dejar Me gusta</strong><small>Solo si el video realmente te agradó.</small></div><span class="optional-badge-v3">Opcional</span></div><div class="find-check-v3">${icon('userPlus','icon-sm')}<div><strong>Puedes suscribirte al canal</strong><small>Esta acción también es opcional.</small></div><span class="optional-badge-v3">Opcional</span></div></div><div class="optional-note-v3">${icon('shield','icon-sm')}El comentario, el Me gusta y la suscripción no son necesarios para obtener el enlace.</div><button class="btn btn-youtube btn-wide" onclick="App.openYoutube()">${icon('youtube')}Abrir búsqueda en YouTube</button>${state.public.youtubeOpened?`<div class="return-panel-v3"><span>${icon('checkCircle','icon-sm')}</span><div><strong>Perfecto. Cuando vuelvas, continúa aquí.</strong><div>Confirma que encontraste el video mostrado arriba.</div></div></div><button class="btn btn-primary btn-wide" onclick="App.goParticipate()">Sí, encontré el video correcto${icon('arrow')}</button>`:''}`)}
function youtubeGuideWaitingMarkup(){return `<div class="guide-waiting-v3"><strong>Primero pulsa “Copiar”</strong><span>Después aparecerá una demostración visual de la búsqueda.</span><div class="guide-waiting-dots-v3"><i></i><i></i><i></i></div></div>`}
function youtubeGuideMarkup(c){return `<div class="search-demo-v3" id="ytGuide"><div class="demo-browser-v3"><i></i><i></i><i></i><div class="demo-search-v3">${esc(c.keyword)}</div></div><div class="demo-results-v3"><div class="demo-track-v3"><div class="demo-result-v3"><div class="demo-thumb-v3"></div><div class="demo-lines-v3"><span></span><span></span></div></div><div class="demo-result-v3"><div class="demo-thumb-v3"></div><div class="demo-lines-v3"><span></span><span></span></div></div><div class="demo-result-v3 target"><img src="${attr(c.videoThumbUrl||c.coverUrl)}" alt="Miniatura objetivo"><div><strong>${esc(c.videoTitle)}</strong>${channelMarkup(c,'guide')}<small class="demo-target-badge-v3">${icon('checkCircle','icon-sm')}Video correcto</small></div></div><div class="demo-result-v3"><div class="demo-thumb-v3"></div><div class="demo-lines-v3"><span></span><span></span></div></div></div></div></div>`}
function replayGuide(){const el=$('#ytGuide');if(!el)return;const clone=el.cloneNode(true);el.replaceWith(clone)}
function copyOptionalComment(i){const prompts=randomPrompts(state.publicCampaign);const text=prompts[i]||'';if(!text)return;copyText(text,'Comentario copiado. Puedes personalizarlo antes de publicarlo.')}
function copyDestination(){const url=state.public.unlockedUrl||'';if(!url)return;copyText(url,'Enlace copiado. Ya puedes pegarlo donde quieras.')}
function participateStage(c){return shell('Sube tu captura','Paso 3',86,`<div class="v3-stage-icon">${icon('camera','icon-lg')}</div><h2 class="stage-title-v3" id="wizardTitle">Por último, sube una captura</h2><p class="stage-subtitle-v3">La captura debe mostrar el video abierto en YouTube y permitir ver claramente su título.</p><div class="capture-reference-v3"><img src="${attr(c.videoThumbUrl||c.coverUrl)}" alt="Video de referencia"><div><small>La captura debe corresponder a:</small><strong>${esc(c.videoTitle)}</strong>${channelMarkup(c)}</div></div><div class="find-checks-v3 capture-checks-expanded-v3"><div class="find-check-v3">${icon('checkCircle','icon-sm')}Que se vea el título del video.</div><div class="find-check-v3">${icon('checkCircle','icon-sm')}Que aparezca la pantalla de YouTube.</div><div class="find-check-v3">${icon('message','icon-sm')}Si dejaste un comentario, puede aparecer en la captura, pero no es obligatorio.</div><div class="find-check-v3">${icon('thumbsUp','icon-sm')}El Me gusta puede aparecer, pero sigue siendo opcional.</div><div class="find-check-v3">${icon('userPlus','icon-sm')}Suscribirse también es opcional y no se exige en la captura.</div><div class="find-check-v3">${icon('checkCircle','icon-sm')}JPG, PNG o WebP · máximo 5 MB.</div></div><label class="upload-zone-v3 ${state.public.screenshotData?'has-image':''}" for="publicShot">${state.public.screenshotData?`<img class="shot-preview-v3" src="${state.public.screenshotData}" alt="Vista previa de la captura"><strong>Captura seleccionada</strong><p>Toca aquí para cambiarla</p>`:`<span class="upload-icon-v3">${icon('upload','icon-lg')}</span><strong>Seleccionar captura</strong><p>Toca aquí para elegir una imagen</p>`}</label><input class="hidden" id="publicShot" type="file" accept="image/jpeg,image/png,image/webp"><div class="confirm-row-v3"><input type="checkbox" id="publicWatched" ${state.public.watched?'checked':''}><label for="publicWatched">Confirmo que esta captura corresponde al video mostrado en el paso anterior.</label></div><button class="btn btn-primary btn-wide" id="submitBtn" onclick="App.submitPublic()">Revisar captura${icon('arrow')}</button>`)}
function reviewStage(){return shell('Comprobando','Verificación',100,`<div class="verifying-v3"><div class="scan-orb-v3">${icon('shield','icon-lg')}</div><h2 class="stage-title-v3" id="wizardTitle">Estamos revisando tu captura</h2><p class="stage-subtitle-v3">El sistema está usando OCR y comparando la imagen con el video solicitado.</p><div class="verify-lines-v3"><div class="verify-line-v3"><span class="verify-dot-v3"></span>Comprobando el archivo</div><div class="verify-line-v3"><span class="verify-dot-v3"></span>Leyendo el texto visible</div><div class="verify-line-v3"><span class="verify-dot-v3"></span>Comparando título y canal</div><div class="verify-line-v3"><span class="verify-dot-v3"></span>Preparando tu enlace</div></div></div>`)}
function unlockedStage(c){const url=state.public.unlockedUrl||'';return shell('Contenido disponible','Completado',100,`<div class="success-v3"><div class="success-mark-v3">${icon('check','icon-xl')}</div><span class="eyebrow-v3">${icon('checkCircle','icon-sm')}Proceso completado</span><h2 class="stage-title-v3" id="wizardTitle" style="margin-top:16px">Tu contenido ya está disponible</h2><p class="stage-subtitle-v3">La validación fue correcta. Puedes abrir el recurso ahora o copiar el enlace.</p><div class="unlock-card-v3"><div class="unlock-cover-v3">${icon(typeIcon(c.contentType),'icon-lg')}</div><div class="unlock-copy-v3"><small>Acceso desbloqueado</small><strong>${esc(c.title)}</strong></div></div><a class="btn btn-success btn-wide" href="${attr(url||'#')}" target="_blank" rel="noopener">${icon(typeIcon(c.contentType))}${actionLabel(c.contentType)}</a><div class="link-row-v3"><div class="link-box-v3">${esc(url)}</div><button class="tiny-btn-v3" type="button" onclick="App.copyDestination()">Copiar</button></div></div>`)}
function hydrateAdFrames(root){const html=state.view==='editor'?(state.editor?.adHtml||''):(state.publicCampaign?.adHtml||'');root.querySelectorAll('[data-ad-frame]').forEach(f=>f.srcdoc=html)}
function bindPublic(){if(state.publicStage==='participate'){const w=$('#publicWatched'),s=$('#publicShot'),btn=$('#submitBtn');const update=()=>{if(btn)btn.disabled=!(state.public.watched&&(!state.publicCampaign.screenshotRequired||!!state.public.screenshotFile))};if(w)w.onchange=e=>{state.public.watched=e.target.checked;update()};if(s)s.onchange=handlePublicShot;update()}}
function scheduleGuide(){if(state.public.guideTimer)clearTimeout(state.public.guideTimer);state.public.guideTimer=setTimeout(()=>{if(state.publicStage==='search'&&!state.public.guideVisible)revealGuide()},3000)}
function revealGuide(){if(state.publicStage!=='search'||state.public.guideVisible)return;if(state.public.guideTimer)clearTimeout(state.public.guideTimer);state.public.guideTimer=null;state.public.guideVisible=true;renderPublic();scrollJourney(false);requestAnimationFrame(()=>replayGuide())}
function publicStart(){state.public.retrying=false;if(state.public.guideTimer)clearTimeout(state.public.guideTimer);Object.assign(state.public,{guideVisible:false,youtubeOpened:false,watched:false,screenshotFile:null,screenshotData:'',submissionId:'',unlockedUrl:''});state.publicStage='search';renderPublic();logEvent('started',state.publicCampaign.id);scrollJourney()}
function copyKeyword(){copyText(state.publicCampaign.keyword,'Texto copiado. Ahora continúa al paso 2.');state.public.guideVisible=true;renderPublic();scrollJourney(false);requestAnimationFrame(()=>replayGuide())}
function goFindVideo(){state.publicStage='identify';renderPublic();scrollJourney()}
function openYoutube(){state.public.youtubeOpened=true;const q=encodeURIComponent(state.publicCampaign.keyword||'');window.open(`https://www.youtube.com/results?search_query=${q}`,'_blank','noopener');renderPublic();logEvent('youtube_opened',state.publicCampaign.id);scrollJourney(false)}
function goParticipate(){state.public.retrying=false;if(state.public.guideTimer)clearTimeout(state.public.guideTimer);state.public.guideTimer=null;state.publicStage='participate';renderPublic();scrollJourney()}
function closePublicWizard(){if(state.publicStage==='review')return;if(state.public.guideTimer)clearTimeout(state.public.guideTimer);state.publicStage='intro';document.body.classList.remove('wizard-open');renderPublic()}
async function handlePublicShot(e){
  const f=e.target.files[0];if(!f)return;
  if(!['image/jpeg','image/png','image/webp'].includes(f.type)||f.size>5*1024*1024||f.size<15*1024){toast('Selecciona una captura JPG, PNG o WebP válida de menos de 5 MB.');e.target.value='';return}
  try{const d=await readImageDimensions(f);if(d.width<400||d.height<250||d.width>12000||d.height>12000){toast('La captura es demasiado pequeña o tiene dimensiones no válidas.');e.target.value='';return}}catch{toast('No pudimos abrir esta imagen. Selecciona otra captura.');e.target.value='';return}
  state.public.screenshotFile=f;const r=new FileReader();r.onload=()=>{state.public.screenshotData=r.result;renderPublic();scrollJourney(false)};r.readAsDataURL(f)
}
async function readImageDimensions(file){
  if('createImageBitmap'in window){const bitmap=await createImageBitmap(file);const out={width:bitmap.width,height:bitmap.height};bitmap.close();return out}
  return new Promise((resolve,reject)=>{const img=new Image();const url=URL.createObjectURL(file);img.onload=()=>{resolve({width:img.naturalWidth,height:img.naturalHeight});URL.revokeObjectURL(url)};img.onerror=()=>{URL.revokeObjectURL(url);reject(new Error('invalid image'))};img.src=url})
}
function showRetryModal(message='No pudimos comprobar que esta captura corresponda al video solicitado. Asegúrate de que el título del video sea visible y vuelve a intentarlo.'){
  showModal(`<div class="retry-modal-icon">${icon('camera','icon-lg')}</div><h3>No pudimos comprobar tu captura</h3><p>${esc(message)}</p><div class="retry-tips"><div>${icon('checkCircle','icon-sm')}Muestra claramente el título del video.</div><div>${icon('checkCircle','icon-sm')}Comprueba que aparezca el canal correcto.</div></div><div class="modal-actions retry-actions"><button class="btn btn-primary btn-wide" onclick="App.retryToStepOne()">${icon('arrowLeft')}Volver al paso 1</button></div>`)
}
function retryToStepOne(){
  closeModal();if(state.public.guideTimer)clearTimeout(state.public.guideTimer);
  state.public.screenshotFile=null;state.public.screenshotData='';state.public.watched=false;state.public.submissionId='';state.public.unlockedUrl='';state.public.youtubeOpened=false;state.public.guideVisible=false;state.public.retrying=true;state.publicStage='search';
  renderPublic();scrollJourney();
}
async function submitPublic(){
  const c=state.publicCampaign;if(!state.public.watched){toast('Confirma que la captura corresponde al video indicado.');return}if(c.screenshotRequired&&!state.public.screenshotFile){toast('Adjunta la captura para continuar.');return}
  state.publicStage='review';renderPublic();scrollJourney();
  try{
    const u=auth.currentUser||await ensureAnonymous();const submissionRef=doc(collection(db,'submissions'));let screenshotPath='';
    if(state.public.screenshotFile){screenshotPath=`campaign-screenshots/${c.id}/${u.uid}/${submissionRef.id}.${extFor(state.public.screenshotFile)}`;await uploadBytes(ref(storage,screenshotPath),state.public.screenshotFile,{contentType:state.public.screenshotFile.type,customMetadata:{campaignId:c.id,submissionId:submissionRef.id}});await logEvent('screenshot_uploaded',c.id)}
    await setDoc(submissionRef,{ownerUid:u.uid,campaignId:c.id,screenshotPath,status:'processing',watched:true,createdAt:serverTimestamp(),updatedAt:serverTimestamp()});
    state.public.submissionId=submissionRef.id;
    const result=await validateScreenshotFn({submissionId:submissionRef.id});
    if(result.data?.approved){await openApprovedContent();return}
    state.publicStage='participate';state.public.screenshotFile=null;state.public.screenshotData='';state.public.watched=false;renderPublic();scrollJourney();showRetryModal();
  }catch(e){
    console.error(e);state.publicStage='participate';state.public.screenshotFile=null;state.public.screenshotData='';state.public.watched=false;renderPublic();scrollJourney();
    const limited=String(e?.code||'').includes('resource-exhausted');showRetryModal(limited?'Has realizado varios intentos seguidos. Espera un momento, vuelve al video y toma una captura nueva donde se vea claramente el título.':'No pudimos completar la comprobación. Vuelve al video, toma una captura nueva y vuelve a intentarlo.');
  }
}
async function openApprovedContent(){
  if(!state.public.submissionId)throw new Error('missing submission');
  const r=await getUnlockedContentFn({submissionId:state.public.submissionId});
  if(!r.data?.url)throw new Error('missing url');
  state.public.unlockedUrl=r.data.url;
  state.publicStage='unlocked';
  renderPublic();
  logEvent('completed',state.publicCampaign.id);
  scrollJourney();
}
function scrollJourney(smooth=true){requestAnimationFrame(()=>{const w=$('.wizard-v3');if(w)w.scrollTo({top:0,behavior:smooth?'smooth':'auto'})})}

function parseSlug(){const hash=decodeURIComponent(location.hash.replace(/^#\/?/,''));if(hash&&hash!=='admin'){history.replaceState(null,'','/'+encodeURIComponent(hash)+'/');return hash}const path=decodeURIComponent(location.pathname).replace(/^\/+|\/+$/g,'');return path&&!['404.html','index.html'].includes(path)?path.split('/')[0]:''}
async function boot(){await loadSettings();const slug=parseSlug();if(slug){await loadPublic(slug);return}if(isAdminUser(auth.currentUser)){state.isAdmin=true;await loadAdminData()}else renderLogin()}
onAuthStateChanged(auth,async u=>{state.user=u;state.isAdmin=isAdminUser(u);const slug=parseSlug();if(slug&&state.view==='loading')await loadPublic(slug);else if(!slug&&state.isAdmin&&state.view!=='admin'&&state.view!=='editor'&&state.view!=='submissions')await loadAdminData();else if(!slug&&!state.isAdmin&&state.view==='loading')renderLogin()});
window.addEventListener('popstate',async()=>{const slug=parseSlug();if(slug)await loadPublic(slug);else if(state.isAdmin)await loadAdminData();else renderLogin()});window.addEventListener('hashchange',async()=>{const slug=parseSlug();if(slug)await loadPublic(slug);else if(state.isAdmin)await loadAdminData();else renderLogin()});

window.App={goAdmin,newCampaign,editCampaign,saveCampaign,removeCampaign,copyLink,openPublic,migrateLocal,editSettings:renderSettings,saveSettings,closeModal,showSubmissions,viewScreenshot,moderateSubmission,secureLegacyCampaigns,logout,publicStart,copyKeyword,goFindVideo,openYoutube,goParticipate,closePublicWizard,submitPublic,replayGuide,copyOptionalComment,copyDestination,retryToStepOne};

showLoading();boot();
